parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "industry_trends": {
      "type": "object",
      "properties": {
        "themes": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "category": { "type": "string", "enum": ["dominant", "emerging", "persistent"] },
              "title": { "type": "string" },
              "detail": { "type": "string" },
              "mentioned_by": {
                "type": "array",
                "items": { "type": "string" }
              }
            },
            "required": ["category", "title", "detail", "mentioned_by"]
          }
        },
        "sources": {
          "type": "array",
          "items": { "type": "string" }
        }
      },
      "required": ["themes", "sources"]
    },
    "competitive_landscape": {
      "type": "object",
      "properties": {
        "companies": {
          "type": "array",
          "description": "Column headers: [target ticker, peer1, peer2, ...]. Same order used in all positions arrays.",
          "items": { "type": "string" }
        },
        "offerings": {
          "type": "array",
          "description": "Each row is a segment that at least two companies share. Only include segments that appear in multiple companies' income statements.",
          "items": {
            "type": "object",
            "properties": {
              "category": {
                "type": "string",
                "description": "The common segment mapped across companies, e.g. 'Cloud Services', 'Advertising Revenue'"
              },
              "positions": {
                "type": "array",
                "description": "One entry per company (same order as companies array). Sourced from income statement data retrieved via the Financial Statement API.",
                "items": {
                  "type": "object",
                  "properties": {
                    "segment_name": {
                      "type": "string",
                      "description": "The exact segment label as it appears in that company's income statement, e.g. 'Amazon Web Services', 'Google Cloud'"
                    },
                    "revenue": {
                      "type": "string",
                      "description": "Most recent fiscal year revenue for this segment, e.g. '$105.5B'"
                    },
                    "revenue_prior_year": {
                      "type": "string",
                      "description": "Prior fiscal year revenue for this segment, e.g. '$90.8B'"
                    },
                    "yoy_growth": {
                      "type": "number",
                      "description": "Year-over-year growth rate as a number, e.g. 16.2 for 16.2% growth, -3.5 for 3.5% decline"
                    },
                    "has_segment": {
                      "type": "boolean",
                      "description": "Whether this company reports a comparable segment. If false, set segment_name to 'N/A', revenue to 'N/A', revenue_prior_year to 'N/A', and yoy_growth to 0."
                    }
                  },
                  "required": ["segment_name", "revenue", "revenue_prior_year", "yoy_growth", "has_segment"]
                }
              }
            },
            "required": ["category", "positions"]
          }
        },
        "data_source": {
          "type": "string",
          "description": "The URL pattern used to retrieve income statements",
          "const": "https://raw.githubusercontent.com/gselez6761/agentic-ai-challenge-data/main/data/income_statements/{TICKER}/income_statement_{TICKER}.json"
        }
      },
      "required": ["companies", "offerings", "data_source"]
    }
  },
  "required": ["industry_trends", "competitive_landscape"]
}
